```class Solution {
public:
    int wordCount(vector<string>& startWords, vector<string>& targetWords) {
        unordered_set<string> startSet(startWords.begin(), startWords.end());
        int res = 0;
        for (const string& target : targetWords) {
            for (int i = 0; i < target.size(); i++) {
                string temp = target.substr(0, i) + target.substr(i + 1);
                if (startSet.count(temp)) res++;
            }
        }
        return res;
    }
};```
